/*@ Extern Coq (array_count_distinct_sorted_spec : list Z -> Z) */
/*@ Import Coq Require Import array_count_distinct_sorted */

int array_count_distinct_sorted(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      n <= INT_MAX &&
      Zlength(l) == n &&
      (forall (i: Z), (0 <= i && i + 1 < n) => l[i] <= l[i + 1]) &&
      IntArray::full(a, n, l)
    Ensure
      __return == array_count_distinct_sorted_spec(l) &&
      IntArray::full(a, n, l)
*/
{
    if (n == 0) {
        return 0;
    }
    int count = 1;
    int i = 1;
    while (i < n) {
        if (a[i] != a[i - 1]) {
            count++;
        }
        i++;
    }
    return count;
}
Require Import ZArith.
Require Import Coq.Lists.List.

Open Scope Z_scope.

Fixpoint array_count_distinct_sorted_from (prev : Z) (l : list Z) : Z :=
  match l with
  | nil => 0
  | x :: xs =>
      (if Z.eq_dec x prev then 0 else 1) +
      array_count_distinct_sorted_from x xs
  end.

Definition array_count_distinct_sorted_spec (l : list Z) : Z :=
  match l with
  | nil => 0
  | x :: xs => 1 + array_count_distinct_sorted_from x xs
  end.
