/*@ Extern Coq (array_count_transitions_spec : list Z -> Z) */
/*@ Import Coq Require Import array_count_transitions */

int array_count_transitions(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == array_count_transitions_spec(l) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int cnt = 0;

    /*@ Inv
          1 <= i && i <= n + 1 &&
          a == a@pre &&
          n == n@pre &&
          cnt == array_count_transitions_spec(sublist(0, i, l)) &&
          IntArray::full(a, n, l)
    */
    for (i = 1; i < n; ++i) {
        if (a[i] != a[i - 1]) {
            cnt++;
        }
    }

    return cnt;
}
